import{_ as r,o as i,c as n,j as a,a as s,a1 as g}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"Genesic_Gaogaigar","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/5.S级/Genesic_Gaogaigar.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/5.S级/Genesic_Gaogaigar.md"}'),o={name:"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/5.S级/Genesic_Gaogaigar.md"};function t(c,e,G,b,p,l){return i(),n("div",null,[...e[0]||(e[0]=[a("h1",{id:"genesic-gaogaigar",tabindex:"-1"},[s("Genesic_Gaogaigar "),a("a",{class:"header-anchor",href:"#genesic-gaogaigar","aria-label":'Permalink to "Genesic_Gaogaigar"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),g('<h1 id="genesic-gaogaigar-1" tabindex="-1">Genesic Gaogaigar <a class="header-anchor" href="#genesic-gaogaigar-1" aria-label="Permalink to &quot;Genesic Gaogaigar&quot;">​</a></h1><p>最终安全装置解除，各部genesic machine便可以与机器人gaigar进行超壮绝的合体——Genesic Final Fusion！！！<br> “Genesic Drive！！！”<br> “Final Fusion！！！”<br> 由此诞生的，便是被称为究极的破坏神的、鬼神般的完全勇者王，勇者最终、也是最初的形态。<br> 遏制再生力量，是破坏的力量。破坏是重新回到起点的希望，是对无限可能性的挑战。<br> 这是，最强的破坏神。这是，勇气的究极形态。<br> 这就是伟大的遗产，宇宙的破坏神，Genesic Gaogaigar！<br> SS+24000<br> Genesic Gaogaigar（实际体积相同）</p><p>作为绿星最终的科技结晶，能使用所有的环境并发挥出完全的力量。</p><p>结构157 装甲80 移动速度1600米/轮<br> 处于飞行状态下可进行加速，加速度1600米/次，最大移动速度27200米/轮。<br> 可搭乘人员：1<br> 体积：94<br> 完美飞行<br> 适应环境：水下 陆地 空中 宇宙<br> 免疫a环境<br> 始源护甲（Genesic Armor）：<br> 效果类似杰达王（King J-Der）的生成护甲（ Generating Armor），但是绿星科技最坚硬的材料和始源灵气（Genesic Aura）供能的防护立场，使其的性能远超生成护甲。<br> 每有5点护甲防御，始源护甲就获得1点基于护甲防御的全吸收。<br> 受到攻击时始源护甲会自动释放出始源灵气，将其组成具有排斥性的粒子会敌人造成伤害。表现为绿色的粒子从装甲的缝隙中飘散而出，并根据敌方的攻击样式形成绿色相同的攻击方式进行反击，这反击会穿过任何检定/防御/吸收/减免，直接对目标造成8L同类型伤害。</p><p>融合（Fusion）<br> 获得G石之人可以和其他物质融为一体，而用G石驱动的Genesic Gaogaigar更是如此，并且通过激发G石的强大算力，为驾驶员构造了一个属于自己的空间，来保护驾驶员。<br>   没有驾驶员的允许，驾驶舱内将处于一个可观测但不可接触的特殊空间之中，对于驾驶舱进行的恶意效果（如灵体穿越机器进入驾驶舱、超级贯穿、低于S级的传送效果等）会被该空间所阻隔；而同样的，处于该异空间效果下的驾驶员也无法与外界建立直接联系（包括但不限于：吃队友增益buff、在驾驶舱内以低于S级传送效果或其他方式穿透驾驶舱建立效果线/感知线等），仅能透过驾驶Genesic Gaogaigar来对外界进行影响（即驾驶员只能共享载具的感知线，仅与载具之间具有效果线），这视为一个SS级别时空来源的异空间效果。当载具被击落摧毁，驾驶员会被迫弹出异空间。<br> 开启/关闭这个异空间效果进行是一个标准动作，该异空间效果默认为开启状态，除非驾驶员主动关闭。</p><p>防护立场（Protect Shade）<br> Genesic Gaogaigar左臂的Protect Shade增幅装置展开，会发出强烈的金色Genesic Aura，构成不断扩散的立场抵挡攻击，强化始源护甲（Genesic Armor）的防护效果。<br> 每轮一次，在应对距离载具30米以上的远程攻击时，防护立场会无效化该远程攻击所带来的一切效果，这是S级时空来源的无敌效果。驾驶员可自由选择该效果对哪一次攻击生效。</p><p>粉碎飞拳（Broken Magnum）<br> 超级机器人传统的飞拳攻击，但不同于只是依靠拳头冲击力造成伤害的其他超级机器人，Genesic Gaogaigar右手搭载了超小型的重力冲击波发生器，并且依靠始源灵气的引导，自由操控飞行的方向，将命中的一切敌人化作光芒！<br> 载具的右臂视为武器伤害27L，造成力场伤害的近战武器。其攻击距离可达650米。这意味着载具拳头可以飞射而出攻击敌人，或是充能后的右臂发出绿色的冲击波轰击敌人。</p><p>双重钻头！（Spiral Drill/Straight Drill）<br> 双腿膝盖上的钻头，极速旋转后能撕裂一切防护，捅穿空间都不在话下。<br> 载具双腿上的钻头视为武器伤害27L，造成穿刺伤害的近战武器。对处于载具触及范围内的敌人，使用该武器进行的攻击可以无视目标所有的天生、护甲防御，这是一个S级别时空来源的效果。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const h=r(o,[["render",t]]);export{_ as __pageData,h as default};
